insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('load-balancing-loss', 'Load Balancing Loss', '', '', ARRAY['load-balancing-loss','load balancing loss','balance loss','auxiliary load loss']::text[], 'Rising', 'An extra nudge during training that stops a mixture-of-experts model from sending every question to the same few experts.', 'A manager who notices three staff are swamped while the rest sip coffee, and starts routing tickets more evenly.', 'A team trains a sparse model and finds two experts handle 80% of tokens; they add a load-balancing term so the idle experts actually learn something.', '[{"text":"The architecture it exists to keep healthy.","id":"mixtureofexperts"},{"text":"It regulates the routing that expert parallelism spreads across chips.","id":"expert-parallelism"}]'::jsonb, 'In a mixture-of-experts layer, a router picks which experts see each token. Left alone, the router collapses onto a favorite few — the rest get no gradient and rot. The load-balancing loss penalizes uneven routing, gently pushing traffic across all experts. Set it too strong and you hurt quality; too weak and experts starve.', 'It is the difference between paying for a big expert model and actually using all of it.', 'An auxiliary loss term proportional to the imbalance between per-expert token counts and their routing probabilities.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('capacity-factor', 'Capacity Factor', '', '', ARRAY['capacity-factor','capacity factor','expert capacity']::text[], 'Rising', 'A dial that sets how many tokens each expert is allowed to handle before it starts dropping the overflow.', 'A restaurant setting covers per table — go over and the extra guests wait outside or get turned away.', 'An engineer raises the capacity factor from 1.0 to 1.25 after noticing tokens were being dropped when too many routed to one expert at once.', '[{"text":"The dropping only matters because of how experts are balanced.","id":"load-balancing-loss"},{"text":"It bounds the buffers that expert parallelism physically allocates.","id":"expert-parallelism"}]'::jsonb, 'Experts run in fixed-size buffers for hardware efficiency, so each has a hard cap: capacity = factor × (tokens ÷ experts). A factor above 1 leaves slack for uneven routing; tokens beyond the cap get dropped or passed through untouched. Higher factor means fewer drops but more wasted compute on half-empty buffers.', 'A quiet quality-versus-cost knob most people never see but that shapes both.', 'The multiplier on the per-expert token buffer size in a MoE layer; overflow tokens are dropped past the cap.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('expert-parallelism', 'Expert Parallelism', '', '', ARRAY['expert-parallelism','expert parallelism','ep sharding']::text[], 'Rising', 'Putting different experts of a mixture-of-experts model on different chips so they run at the same time.', 'Splitting a big kitchen into stations — grill, salad, dessert — each on its own cook, plates flying in parallel.', 'A lab serving a 100-expert model places ten experts per GPU across ten GPUs, so a token only travels to the chip holding its chosen expert.', '[{"text":"The architecture being spread across hardware.","id":"mixtureofexperts"},{"text":"Uneven load turns the all-to-all into a stall.","id":"load-balancing-loss"}]'::jsonb, 'Unlike splitting one dense layer across chips, expert parallelism assigns whole experts to devices. The catch is the all-to-all shuffle: every token must be shipped to wherever its expert lives and the result shipped back, so network bandwidth, not math, often becomes the bottleneck. Uneven routing makes it worse — one overloaded chip stalls the rest.', 'It is what makes trillion-parameter models affordable to serve without every chip holding every weight.', 'A model-parallel scheme that shards experts across devices, requiring all-to-all communication to route tokens and gather outputs.', 'Architectures', 60, ARRAY['seed','architectures']::text[]),
  ('tool-use', 'Tool Use', '', '', ARRAY['tool-use','tool use','using tools']::text[], 'Core', 'Letting a model reach outside its own head — run code, search the web, hit an API — instead of guessing from memory.', 'A smart person who, instead of estimating, just picks up a calculator, opens a browser, or makes a phone call.', 'Asked for today’s weather, the model does not invent a forecast — it calls a weather API and reads back the real number.', '[{"text":"The structured version, where the model fills in named arguments.","id":"function-calling"},{"text":"A tool call plus its returned observation, run over and over.","id":"agent-loop"},{"text":"It reduces made-up answers by fetching real ones.","id":"hallucination"}]'::jsonb, 'The model does not run tools itself; it emits a request to use one, a surrounding program runs it, and the result comes back as new text in the context. This turns a frozen, all-knowing guesser into something that can act and observe. The whole agent field is basically tool use in a loop.', 'The single feature that turns a chatbot into something that can actually get things done.', 'The model outputs a tool invocation; an external runtime executes it and feeds the result back into the context window.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('function-calling', 'Function Calling', '', '', ARRAY['function-calling','function calling','function call']::text[], 'Core', 'The model outputs a clean, structured request to run a specific function — name plus arguments — instead of free text.', 'Filling out a proper order form with the exact fields, rather than scrawling your request on a napkin.', 'You describe a `send_email(to, subject, body)` function; the model replies with those three fields filled in, and your code sends it.', '[{"text":"The broader idea it makes reliable.","id":"tool-use"},{"text":"The contract that says what the arguments must look like.","id":"tool-schema"},{"text":"What comes back after the function runs.","id":"tool-result"}]'::jsonb, 'You hand the model a list of functions and their argument shapes. When it decides one applies, it returns valid structured output — usually JSON — matching that shape, which your program parses and executes. It is the backbone of tool use because it makes the model’s intent machine-readable instead of something you have to scrape out of a sentence.', 'It is what makes a model a reliable trigger for real actions, not just a text box.', 'Constrained generation of a JSON payload matching a declared function schema, dispatched by the host application.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('react', 'ReAct', '', '', ARRAY['react','reason and act','reason+act','reasoning and acting']::text[], 'Core', 'A pattern where the model alternates between thinking out loud and taking an action, each step informing the next.', 'A detective who mutters a theory, checks one clue, updates the theory, checks another — reasoning and legwork taking turns.', '“I need the population — let me search.” It searches, reads the result, then reasons: “Now I can compute the density,” and calls the calculator.', '[{"text":"The think-out-loud half of the pattern.","id":"chainofthought"},{"text":"The take-an-action half.","id":"tool-use"},{"text":"The result an action returns before the next thought.","id":"observation"}]'::jsonb, 'ReAct interleaves a reasoning trace with tool actions and their observations, so the model’s next thought is grounded in what it just saw rather than pure speculation. It made early agents far more reliable than plan-everything-upfront approaches, because the model can course-correct after each real result. The reasoning steps also make its behavior legible when something goes wrong.', 'The recipe behind most working agents — think a little, act a little, repeat.', 'An agent loop interleaving chain-of-thought tokens with tool actions and observations fed back into context.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('planning', 'Planning', '', '', ARRAY['planning','agent planning','task planning']::text[], 'Core', 'The model sketching the steps to reach a goal before it starts doing them.', 'Writing a to-do list for a road trip — book the car, map the route, pack — instead of just driving off.', 'Told to “launch a newsletter,” the agent first lays out: pick a platform, draft a template, import contacts, schedule the first send.', '[{"text":"Breaking the goal into the pieces a plan is made of.","id":"task-decomposition"},{"text":"Redoing the plan when reality disagrees.","id":"replanning"},{"text":"Carrying the plan out, step by step.","id":"plan-execution"}]'::jsonb, 'Planning separates deciding what to do from doing it, which helps on long tasks where a single greedy step would wander off. Plans can be made once up front or revised as reality intrudes. The honest catch: models are decent at plausible-sounding plans and worse at plans that survive contact with a messy environment, which is why replanning matters.', 'It is what lets an agent tackle a big ask instead of only bite-sized prompts.', 'Generating an ordered sequence of subgoals or actions before execution, optionally revised as observations arrive.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('orchestration', 'Orchestration', '', '', ARRAY['orchestration','agent orchestration','workflow orchestration']::text[], 'Core', 'The layer that decides which model, tool, or agent runs when, and how their outputs flow together.', 'A conductor — not playing any instrument, just cueing each section in at the right moment.', 'A support system routes a refund question to a billing agent, waits for its answer, then hands it to a drafting agent to write the reply.', '[{"text":"A common orchestration shape: many specialized agents.","id":"multi-agent"},{"text":"Passing control from one agent to another.","id":"handoff"},{"text":"The repeating cycle it often coordinates.","id":"agent-loop"}]'::jsonb, 'Orchestration is the plumbing above the models: sequencing steps, passing state between them, retrying failures, enforcing limits. It can be rigid (a fixed workflow you coded) or dynamic (a model deciding the next move each turn). Most production “AI apps” are 20% model and 80% orchestration — the boring glue is where reliability actually comes from.', 'Where a demo becomes a product — the coordination that makes many parts behave like one.', 'The control layer that sequences model calls, tool executions, and agent handoffs, managing state and error handling between them.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('multi-agent', 'Multi-Agent', '', '', ARRAY['multi-agent','multi agent','multiagent','agent team']::text[], 'Rising', 'Several specialized agents working together on one task instead of one agent doing everything.', 'A film crew — director, editor, sound — each expert at one job, coordinating toward the same movie.', 'A research task uses a planner agent to outline, several worker agents to gather sources in parallel, and a writer agent to stitch the report.', '[{"text":"The coordination layer that keeps the team in sync.","id":"orchestration"},{"text":"The boss agent that assigns and reviews.","id":"supervisor-agent"},{"text":"The agents doing the actual pieces.","id":"worker-agent"}]'::jsonb, 'Splitting a job across agents lets each hold a focused role and prompt, and lets some run in parallel. The cost is coordination: agents talk past each other, duplicate work, or compound each other’s mistakes. Often a single well-prompted agent beats an elaborate committee — multi-agent earns its keep mainly when the subtasks are genuinely independent.', 'Tempting for hard problems, but more agents means more ways to fail — reach for it only when the work truly splits.', 'Multiple agent instances with distinct roles and contexts, coordinated via a shared orchestrator or message passing.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('agent-loop', 'Agent Loop', '', '', ARRAY['agent-loop','agent loop','agentic loop','act-observe loop']::text[], 'Core', 'The heartbeat of an agent — think, act, observe, repeat, until the task is done.', 'Cooking from a recipe: read a step, do it, check the pot, decide the next step, and keep going until it’s served.', 'An agent reads a bug report, runs the tests, sees them fail, edits a file, reruns the tests, and loops until they pass.', '[{"text":"The think-then-act pattern that fills each turn.","id":"react"},{"text":"What the model produces each iteration.","id":"action-space"},{"text":"The result folded back in before the next turn.","id":"observation"}]'::jsonb, 'Each turn the model gets the current context, decides on an action, the action runs, and its result is appended before the next turn. This loop is where all the agent’s power and all its danger live — it can chip away at a long task, or it can spin forever, repeat a mistake, or blow the budget. Good agents have exit conditions and step limits baked in.', 'The core mechanic to understand — capability, cost, and runaway risk all come from this repeat.', 'A control loop that appends each action’s observation to context and re-invokes the model until a stop condition.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('autonomy', 'Autonomy', '', '', ARRAY['autonomy','autonomous','agent autonomy','autonomy level']::text[], 'Core', 'How much an agent is trusted to act on its own before it has to stop and ask a human.', 'The difference between an intern who checks every email with you and a deputy you let sign things while you’re away.', 'A coding agent with low autonomy shows each edit for approval; with high autonomy it edits, tests, and commits before you ever look.', '[{"text":"The checkpoint that lowers autonomy on risky steps.","id":"approval-gate"},{"text":"More autonomy means longer unattended loops.","id":"agent-loop"},{"text":"A common high-autonomy application.","id":"agentic-coding"}]'::jsonb, 'Autonomy is a spectrum, not a switch — from suggest-only, to act-with-approval, to fully self-directed. More autonomy means more done unattended and more that can go wrong unattended. The practical craft is matching the level to the stakes: high for reversible, low-cost actions; a human gate for anything expensive or irreversible.', 'The core trust dial — set it by how bad an unsupervised mistake would be.', 'The degree to which the agent loop runs without human confirmation between actions.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('tool-schema', 'Tool Schema', '', '', ARRAY['tool-schema','tool schema','tool definition','tool spec']::text[], 'Core', 'The spec sheet that tells the model what a tool does, what it’s called, and exactly what inputs it takes.', 'The label on a control panel — button name, what it does, and which knobs it needs set first.', 'A `search(query, max_results)` schema tells the model the tool’s name, that `query` is a required string, and `max_results` an optional number.', '[{"text":"What the model produces to satisfy the schema.","id":"function-calling"},{"text":"The broader capability the schema enables.","id":"tool-use"},{"text":"A stricter form that validates the call against the schema.","id":"structured-tool-use"}]'::jsonb, 'Each tool is described in a structured format — usually JSON Schema — with a name, a natural-language description, and typed parameters. The model reads these descriptions to decide which tool fits and how to fill its arguments, so the wording matters as much as the types: a vague description means the model misuses the tool. It is the contract between the model’s intent and your code.', 'Half of tool reliability is just writing clear tool descriptions.', 'A machine-readable declaration (typically JSON Schema) of a tool’s name, description, and parameter types that constrains the model’s call.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('api-calling', 'API Calling', '', '', ARRAY['api-calling','api calling','calling apis','api tool']::text[], 'Core', 'An agent reaching out to an external web service to fetch data or make something happen.', 'Phoning another department to get a record pulled or an order placed — you don’t do it yourself, you ask the right desk.', 'A travel agent hits an airline’s API to check live seat availability rather than guessing which flights exist.', '[{"text":"The general capability this is one flavor of.","id":"tool-use"},{"text":"A standard protocol for exposing tools and data to models.","id":"mcp"},{"text":"What the API sends back into the loop.","id":"tool-result"}]'::jsonb, 'Most useful agent tools are thin wrappers around APIs: the model picks the call and arguments, your code makes the HTTP request, and the response returns as an observation. The hard parts are unglamorous — auth tokens, rate limits, pagination, and errors the model has to interpret and retry. The model supplies intent; the plumbing supplies reliability.', 'It is how an agent plugs into the systems you already run — CRM, calendar, payments.', 'A tool whose execution issues an authenticated HTTP request to an external service and returns the parsed response to context.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('code-interpreter', 'Code Interpreter', '', '', ARRAY['code-interpreter','code interpreter','python tool','code execution tool']::text[], 'Core', 'A tool that lets the model write and actually run code, then read what it printed.', 'Giving the model a scratch computer — it can type a program, hit run, and see the output, not just imagine it.', 'Asked to analyze a spreadsheet, the model writes Python to load the file, computes the averages, and reports the numbers the code produced.', '[{"text":"The isolation that makes running its code safe.","id":"sandbox-execution"},{"text":"The general act of running things for the model.","id":"tool-use"},{"text":"A close cousin aimed at writing software, not just computing.","id":"agentic-coding"}]'::jsonb, 'Instead of doing arithmetic or data wrangling in its head — where it quietly makes errors — the model emits code that runs in a sandboxed environment and returns real output. This is a huge reliability win for anything computational, and it doubles as a general tool: if there’s a library for it, the model can use it. The sandbox is essential, since running model-written code is exactly as risky as it sounds.', 'It turns a model that fumbles math into one that computes exact answers.', 'A tool that executes model-generated code in an isolated runtime and returns stdout, errors, and artifacts as observations.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('computer-use', 'Computer Use', '', '', ARRAY['computer-use','computer use','desktop agent','gui agent']::text[], 'Rising', 'Letting a model drive a real computer the way a person does — looking at the screen, moving the mouse, typing.', 'A remote assistant on a screen-share who can see your desktop and click around to get things done.', 'Asked to file an expense, the agent takes a screenshot, finds the form fields, clicks them, types the amounts, and hits submit.', '[{"text":"A narrower version scoped to the web browser.","id":"browser-agent"},{"text":"The high-stakes actions that argue for a human checkpoint.","id":"approval-gate"},{"text":"Its reliance on reading images.","id":"observation"}]'::jsonb, 'The model is fed screenshots and returns actions — click at these coordinates, type this, scroll — in a loop, letting it use any app without a dedicated API. It is powerful and brittle: pixel-level targeting misfires, pages shift, and a wrong click can do real damage. Because it can touch anything on screen, it is one of the higher-risk agent modes and usually runs behind confirmations.', 'It promises automation of any app, but reliability and safety are the whole ballgame.', 'A vision-driven agent loop that maps screenshots to GUI actions (click, type, scroll) via coordinates.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('browser-agent', 'Browser Agent', '', '', ARRAY['browser-agent','browser agent','web agent','web browsing agent']::text[], 'Rising', 'An agent that navigates the web for you — opening pages, clicking, filling forms, reading results.', 'An intern you send off to “go find this online and book it,” who comes back with the confirmation.', '“Find the cheapest direct flight next Friday and start the booking” — the agent opens a travel site, searches, compares, and fills the passenger form.', '[{"text":"The broader case of driving a whole computer.","id":"computer-use"},{"text":"Malicious page content can hijack the loop.","id":"hallucination"},{"text":"A read-only cousin that just fetches and searches.","id":"search-tool"}]'::jsonb, 'Browser agents work over the page — sometimes via the DOM, sometimes via screenshots — issuing navigate, click, and type actions in a loop. They stumble on the modern web’s defenses: logins, captchas, pop-ups, and layouts that change under them. And because they act on live sites, prompt-injection from a malicious page is a genuine risk, so what they’re allowed to do should be fenced.', 'The dream of “just do this task on the web,” bounded by how hostile the real web is.', 'An agent that controls a browser via DOM or vision, emitting navigation and interaction actions against live pages.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('router-agent', 'Router Agent', '', '', ARRAY['router-agent','router agent','routing agent','dispatcher agent']::text[], 'Rising', 'A lightweight agent whose only job is to read a request and send it to the right specialist.', 'A receptionist who doesn’t solve your problem but knows exactly which office to point you to.', 'An incoming message hits the router, which decides “this is a billing issue” and forwards it to the billing agent rather than answering itself.', '[{"text":"The multi-agent setups it steers traffic within.","id":"multi-agent"},{"text":"The boss that a router often reports into.","id":"supervisor-agent"},{"text":"Passing the request onward once routed.","id":"handoff"}]'::jsonb, 'A router agent classifies or triages input and dispatches it, keeping specialized agents focused and cheap to run. It is usually a small, fast model since the decision is simple. The failure mode is misrouting — send a question to the wrong specialist and the whole chain produces a confident, off-target answer, so routers are worth evaluating on their own.', 'A cheap way to make a pile of narrow agents feel like one smart assistant.', 'A classifier-style agent that maps requests to downstream agents or tools, typically run on a small fast model.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('supervisor-agent', 'Supervisor Agent', '', '', ARRAY['supervisor-agent','supervisor agent','manager agent','lead agent']::text[], 'Rising', 'The agent that assigns work to other agents and checks what they hand back.', 'A team lead who breaks up the project, parcels out tasks, and reviews everyone’s work before it ships.', 'A supervisor agent splits a research brief into three questions, dispatches a worker per question, then reviews and merges their findings.', '[{"text":"The agents it hands tasks to.","id":"worker-agent"},{"text":"The team structure it sits atop.","id":"multi-agent"},{"text":"Breaking the goal into assignable pieces.","id":"task-decomposition"}]'::jsonb, 'The supervisor holds the overall goal and state, decides who does what, and decides when the job is done — a hub-and-spoke pattern that keeps workers simple. Its risk is being a single point of confusion: if its judgment about task completion or quality is off, every worker below it inherits the error. It trades coordination overhead for focus.', 'The pattern that makes a swarm of agents accountable to one plan.', 'An orchestrating agent that decomposes tasks, delegates to worker agents, and evaluates their outputs against the goal.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('worker-agent', 'Worker Agent', '', '', ARRAY['worker-agent','worker agent','sub-agent','subagent','specialist agent']::text[], 'Rising', 'A focused agent that does one assigned piece of a larger job and reports back.', 'A specialist contractor called in for the wiring — does that one part well, then hands it back to the general contractor.', 'A worker agent is told only “summarize these five sources,” with no view of the wider project, and returns a tidy summary.', '[{"text":"The boss that assigns and reviews its work.","id":"supervisor-agent"},{"text":"The piece of the job it owns.","id":"subtask"},{"text":"Handing its result back up.","id":"handoff"}]'::jsonb, 'Worker agents get a narrow task, a tight prompt, and often no memory of the broader goal — which is a feature, since a smaller scope means fewer ways to wander. Several can run in parallel. Their limitation is exactly their strength: with no big picture, they can optimize their slice in a way that doesn’t serve the whole, so the supervisor’s framing of each task carries a lot of weight.', 'The unglamorous engine of multi-agent work — narrow scope is what keeps them reliable.', 'A scoped agent instance executing a delegated subtask with limited context, returning results to its supervisor.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('handoff', 'Handoff', '', '', ARRAY['handoff','hand-off','agent handoff','control handoff']::text[], 'Rising', 'One agent passing the task — and the context it needs — to another agent.', 'A relay runner passing the baton, except what’s passed is everything the next runner needs to know.', 'A triage agent gathers the customer’s details, then hands off to a returns agent with the order number and reason already filled in.', '[{"text":"The systems where handoffs happen constantly.","id":"multi-agent"},{"text":"What gets carried across the handoff.","id":"agent-state"},{"text":"The layer that routes these transfers.","id":"orchestration"}]'::jsonb, 'A handoff transfers control plus enough state for the receiver to continue without re-asking. The quality of a multi-agent system lives here: pass too little and the next agent flounders; pass a giant dump and it drowns in irrelevance. Clean handoffs — the right summary at the right moment — are what separate a smooth agent chain from a game of telephone.', 'The seam where multi-agent systems feel either seamless or maddeningly repetitive.', 'Transfer of control and relevant state from one agent to another, typically via a structured message or shared context.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('scratchpad', 'Scratchpad', '', '', ARRAY['scratchpad','scratch pad','working notes','thinking scratchpad']::text[], 'Core', 'A space where the model writes intermediate thoughts and notes to itself while working through a problem.', 'The margin of an exam where you scribble your working before writing the final answer in the box.', 'Before answering a logic puzzle, the model jots the constraints and rules out options in a scratchpad, then gives the clean answer.', '[{"text":"The reasoning style a scratchpad enables.","id":"chainofthought"},{"text":"Longer-lived notes that outlast a single scratchpad.","id":"agent-memory"},{"text":"Where it fits in the think-act rhythm.","id":"react"}]'::jsonb, 'Letting a model externalize its reasoning into text it can re-read improves hard, multi-step problems — it is chain-of-thought given a place to live. In agents, the scratchpad also holds notes across loop turns: what’s been tried, what’s left. Sometimes it is shown to the user, sometimes hidden; either way it is scaffolding for thinking, not the deliverable.', 'Why “show your work” prompting makes models measurably more correct.', 'A region of context the model writes intermediate reasoning or state into, re-read on subsequent steps.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('agent-memory', 'Agent Memory', '', '', ARRAY['agent-memory','agent memory','long-term memory','persistent memory']::text[], 'Core', 'What an agent remembers beyond the current conversation — facts, past steps, preferences it can pull back up later.', 'A notebook the assistant keeps between meetings, so you don’t have to reintroduce yourself every time.', 'An agent remembers from last week that you prefer metric units and morning meetings, and applies that without being told again.', '[{"text":"The frozen limit that memory works around.","id":"inference"},{"text":"How stored memories are usually found again.","id":"embeddings"},{"text":"The retrieve-then-answer pattern it borrows from.","id":"rag"}]'::jsonb, 'Because the context window is finite and resets, real continuity needs external memory: notes stored in a database, often as embeddings, retrieved when relevant and slotted back into context. The design questions are the hard part — what’s worth saving, when to recall it, when to forget. Done badly, it either forgets everything or drags in stale, irrelevant detail.', 'The difference between an assistant that knows you and one that meets you fresh each time.', 'External storage (often a vector store) that persists facts and history across sessions, retrieved into context on demand.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('reflection', 'Reflection', '', '', ARRAY['reflection','self-reflection','reflexion']::text[], 'Rising', 'The agent pausing to critique its own work and decide what to fix before moving on.', 'Rereading your own email and thinking “that middle paragraph is a mess” before you hit send.', 'After drafting code, the agent reviews it, notices an unhandled edge case, and revises before running the tests.', '[{"text":"What reflection leads to once a flaw is spotted.","id":"self-correction"},{"text":"The loop reflection is one step within.","id":"agent-loop"},{"text":"Grounding the critique in real feedback.","id":"tool-result"}]'::jsonb, 'Reflection adds a step where the model evaluates its last output against the goal and produces feedback it then acts on. It reliably catches some classes of mistakes and improves quality — but it has a ceiling, because the same model doing the work is grading it, and it can be blind to its own blind spots or talk itself into false confidence. External signals like tests or tool results make reflection much sharper.', 'A cheap quality bump for agent output, with a real limit — a model can’t always see its own errors.', 'A step where the model critiques its prior output and generates corrective feedback fed into the next iteration.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('self-correction', 'Self-Correction', '', '', ARRAY['self-correction','self correction','self-repair','error correction']::text[], 'Rising', 'An agent noticing it went wrong and fixing the mistake on its own, without a human stepping in.', 'A cook tasting the sauce, realizing it’s over-salted, and adding cream to pull it back — mid-service, no manager needed.', 'The agent runs its code, sees a stack trace, reads the error, patches the offending line, and reruns until it passes.', '[{"text":"The critique step that precedes the fix.","id":"reflection"},{"text":"The error signals that make correction trustworthy.","id":"observation"},{"text":"When correction means redoing the whole plan.","id":"replanning"}]'::jsonb, 'Self-correction is reflection turned into action: detect the error, diagnose it, retry. It works best when the environment gives honest feedback — failing tests, API errors, a search that returns nothing — because that grounds the fix in reality rather than the model’s guesses. Without such signals it can “correct” a right answer into a wrong one, so the quality of the error signal is everything.', 'What lets agents recover from stumbles instead of confidently shipping the stumble.', 'The act of detecting a failure from feedback and revising the action, ideally driven by external error signals.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('agentic-coding', 'Agentic Coding', '', '', ARRAY['agentic-coding','agentic coding','ai coding agent','autonomous coding']::text[], 'Rising', 'An AI that writes software by working in a loop — editing files, running tests, fixing failures — not just suggesting snippets.', 'The jump from a spellchecker that flags words to an editor who rewrites the chapter, checks it reads well, and revises.', 'Given “add dark mode,” the agent finds the relevant files, makes the edits across them, runs the build, and fixes what breaks.', '[{"text":"The autocomplete-era predecessor it grew out of.","id":"copilot"},{"text":"A named class of these systems.","id":"swe-agent"},{"text":"Running code to check the work.","id":"code-interpreter"}]'::jsonb, 'Agentic coding puts a model inside a real dev loop with tools: read the repo, edit, run tests, read the failures, try again. Tight feedback from the compiler and tests is what makes it work — the environment tells the model when it’s wrong, so it can self-correct. It shines on well-scoped, testable changes and struggles on ambiguous, cross-cutting design where there’s no quick signal.', 'The shift from autocomplete to a teammate who can take a ticket end to end.', 'A coding agent loop combining file edits, test execution, and error feedback for iterative self-correction.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('copilot', 'Copilot', '', '', ARRAY['copilot','coding copilot','ai copilot','code assistant']::text[], 'Core', 'An AI that rides along as you work, suggesting the next line or block for you to accept or reject.', 'A knowledgeable passenger reading you the next turn — you’re still driving, they’re just calling it out.', 'You start typing a function to parse a date; the copilot greys in the whole body, and you press Tab to accept.', '[{"text":"Where the copilot idea grows up into autonomy.","id":"agentic-coding"},{"text":"The low end of the autonomy spectrum it lives on.","id":"autonomy"},{"text":"The raw capability underneath it.","id":"code-generation"}]'::jsonb, 'The copilot pattern keeps the human in the driver’s seat: the model proposes, you dispose, one suggestion at a time. It became the default way AI entered coding and then writing, because low autonomy makes it safe and easy to trust. It is now often a stepping stone to more agentic modes, where the same underlying model stops waiting for you to accept each step.', 'The gateway drug for AI assistance — helpful precisely because it never acts without you.', 'A low-autonomy assistant that proposes inline completions for human acceptance rather than executing autonomously.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('code-generation', 'Code Generation', '', '', ARRAY['code-generation','code generation','codegen','code synthesis']::text[], 'Core', 'A model producing working source code from a description of what you want.', 'Describing a shelf to a carpenter and getting back the cut, drilled, ready-to-assemble pieces.', '“Write a function that validates an email address” — the model returns a complete, runnable function with the regex and edge cases.', '[{"text":"Its risk: plausible code calling functions that don’t exist.","id":"hallucination"},{"text":"The assistant form most people first met it as.","id":"copilot"},{"text":"Running the output to verify it.","id":"code-interpreter"}]'::jsonb, 'Code generation works because code is text with rigid structure and abundant training examples, and it comes with a rare gift: you can often run the output to check it. That testability is why coding became AI’s strongest applied domain. The catch is confident-but-wrong code — subtle bugs, made-up library functions — so generated code still needs review and tests, not blind trust.', 'The capability that made AI immediately, measurably useful to a huge profession.', 'Generating syntactically valid, functional source code from natural-language or partial-code prompts.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('swe-agent', 'SWE Agent', '', '', ARRAY['swe-agent','swe agent','software engineering agent','swe-bench agent']::text[], 'Rising', 'An agent built to resolve real software issues end to end — read the repo, write the fix, prove it works.', 'Handing a junior engineer a bug ticket and getting back a tested, ready-to-merge pull request.', 'Given a GitHub issue, the agent locates the buggy files, edits them, runs the test suite, and produces a passing patch.', '[{"text":"The broader practice it’s the sharpest example of.","id":"agentic-coding"},{"text":"The kind of proof it runs to validate a fix.","id":"sandbox-execution"},{"text":"How it recovers when tests fail.","id":"self-correction"}]'::jsonb, 'SWE agents are the benchmark-driven face of agentic coding, measured on suites like SWE-bench where the task is “given this repo and this issue, produce a patch that passes the hidden tests.” Progress here has been fast because the scoring is objective. The gap to everyday work is that real tickets are underspecified and touch design, review, and taste — things a hidden test can’t capture.', 'The clearest yardstick for “can AI actually do engineering work,” with a real-world asterisk.', 'An agent evaluated on repository-level issue resolution, producing patches validated against held-out tests.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('tool-calling', 'Tool Calling', '', '', ARRAY['tool-calling','tool calling','tool call','calling tools']::text[], 'Core', 'The concrete act of a model choosing a tool and issuing the request to run it, mid-response.', 'Reaching for the right implement on the workbench the moment the task needs it — grab the wrench, not just describe wrenches.', 'Halfway through answering, the model emits a call to the `get_stock_price` tool with `ticker: "AAPL"` and pauses for the result.', '[{"text":"The structured-output mechanism behind it.","id":"function-calling"},{"text":"The umbrella idea it realizes.","id":"tool-use"},{"text":"What the runtime hands back afterward.","id":"tool-result"}]'::jsonb, 'Tool calling is the mechanical event inside tool use: the model outputs a structured request naming the tool and its arguments, the runtime pauses generation, runs it, and resumes with the result appended. Modern models are trained to do this natively, often calling several tools in one turn. The reliability question is whether it picks the right tool and fills the arguments correctly.', 'The moment your model stops talking and starts doing — literally the trigger for action.', 'The model emitting a structured tool invocation that suspends generation until the runtime returns a result.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('structured-tool-use', 'Structured Tool Use', '', '', ARRAY['structured-tool-use','structured tool use','validated tool use','typed tool calls']::text[], 'Rising', 'Making the model’s tool requests conform strictly to a defined shape, so they can’t come out malformed.', 'A form that won’t submit until every required field is filled with the right kind of value — no half-finished orders slip through.', 'The model must return `{amount: number, currency: string}`; the system rejects or repairs any call missing a field or with the wrong type.', '[{"text":"The schema it enforces against.","id":"tool-schema"},{"text":"The call it makes trustworthy.","id":"tool-calling"},{"text":"The structured-output mechanism it tightens.","id":"function-calling"}]'::jsonb, 'Rather than hoping the model emits valid arguments, structured tool use constrains generation to a schema — via grammars, constrained decoding, or validate-and-retry — so the output is guaranteed parseable. This removes a whole category of flaky failures where a stray character broke the JSON. The tradeoff is a little rigidity and setup, in exchange for calls your code can trust.', 'The unglamorous reliability layer that keeps agents from breaking on a misplaced comma.', 'Enforcing schema conformance on tool-call arguments via constrained decoding or validation-and-repair.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('tool-result', 'Tool Result', '', '', ARRAY['tool-result','tool result','tool output','tool response']::text[], 'Core', 'What comes back after a tool runs — the data or message the model reads to decide its next move.', 'The number the calculator shows after you press equals; you read it, then keep going.', 'The weather tool returns `{temp: 14, condition: "rain"}`; the model reads it and writes “Bring an umbrella — it’s 14° and raining.”', '[{"text":"The action that produced it.","id":"tool-calling"},{"text":"Its role in the perceive-then-act loop.","id":"observation"},{"text":"The loop it feeds back into.","id":"agent-loop"}]'::jsonb, 'The tool result is appended to the context as the fruit of an action, and the model’s next turn is conditioned on it. Its format matters more than people expect: a clean, relevant result guides the model well, while a giant raw dump wastes context and buries the signal. Errors count as results too — a good agent reads a failure and adapts rather than plowing ahead.', 'Feed agents tidy results, not fire-hoses — how you shape tool output shapes the answer.', 'The output of a tool execution appended to context, conditioning the model’s subsequent generation.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('observation', 'Observation', '', '', ARRAY['observation','observations','percept','feedback observation']::text[], 'Core', 'Whatever the agent perceives from the world after it acts — the feedback it reasons over next.', 'Looking up after each chess move to see how your opponent responded before planning the next one.', 'The agent clicks “submit,” and its observation is the confirmation page — or the red error banner telling it something went wrong.', '[{"text":"The tool version of an observation.","id":"tool-result"},{"text":"The set of moves the agent chooses among.","id":"action-space"},{"text":"The perceive-act pattern it anchors.","id":"react"}]'::jsonb, 'Observation is the perception half of the loop: tool results, screenshots, API responses, error messages — the environment’s reply to the agent’s action. Grounding each step in fresh observations is what separates an agent from a model spinning stories in a vacuum. The catch is that observations can be noisy, huge, or adversarial, and the agent has to read them correctly to act well.', 'Agents are only as smart as what they can actually see after each move.', 'The environment’s response to an action, fed back into context as the input for the next reasoning step.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('action-space', 'Action Space', '', '', ARRAY['action-space','action space','set of actions','available actions']::text[], 'Core', 'The full set of moves an agent is allowed to make at any given step.', 'The legal moves in a board game — you can only do what the rules permit, however clever your plan.', 'A browsing agent’s action space is click, type, scroll, and navigate; it can’t do anything outside that menu, no matter what it wants.', '[{"text":"A single choice drawn from the action space.","id":"tool-calling"},{"text":"The world the actions operate on.","id":"environment"},{"text":"Fencing risky actions behind approval.","id":"approval-gate"}]'::jsonb, 'The action space defines the agent’s reach — which tools it can call, which operations it can perform. Its size is a real design tension: too small and the agent can’t solve the task; too large and it gets lost choosing, or gains powers you didn’t mean to grant. Constraining the action space is also a core safety lever, since an agent literally cannot do what isn’t in it.', 'Bound this deliberately — it’s both what the agent can achieve and what it can wreck.', 'The enumerated set of tools and operations available to the agent at each decision step.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('environment', 'Environment', '', '', ARRAY['environment','agent environment','execution environment']::text[], 'Core', 'The world an agent acts in — the files, apps, websites, or systems it can touch and change.', 'The kitchen a chef works in: the ingredients, appliances, and mess that respond to what they do.', 'For a coding agent the environment is the repository, the shell, and the test runner; its actions edit files and its observations are the test output.', '[{"text":"A safely-walled environment for risky actions.","id":"sandbox-execution"},{"text":"What the agent can do within it.","id":"action-space"},{"text":"What it perceives back from it.","id":"observation"}]'::jsonb, 'The environment is everything outside the model that the agent perceives and affects. Its properties shape everything: does it give clear feedback, is it safe to fail in, can actions be undone? A sandboxed environment lets an agent try, break things, and learn cheaply; a live production environment turns every mistake real. Designing the environment is often as important as the agent itself.', 'Where an agent runs decides how safely it can be allowed to fail.', 'The external system an agent observes and acts on, defining feedback signals, state, and blast radius.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('trajectory', 'Trajectory', '', '', ARRAY['trajectory','agent trajectory','episode trace','run trace']::text[], 'Core', 'The full recorded path of an agent through a task — every thought, action, and observation, in order.', 'A hiker’s GPS track: not just where they ended up, but the whole winding route they took to get there.', 'Debugging a failed run, you replay its trajectory and see it looped between two files three times before giving up.', '[{"text":"A single sampled trajectory, often for training.","id":"rollout"},{"text":"The loop that generates each step of it.","id":"agent-loop"},{"text":"The evolving state it records.","id":"agent-state"}]'::jsonb, 'A trajectory is the complete step-by-step record of one run, and it is the primary artifact for understanding agents — where it went wrong, where it wasted turns, whether the reasoning made sense. Trajectories are also training and evaluation data: good ones teach the model, and comparing them across runs reveals patterns. Reading trajectories is the closest thing agent builders have to debugging by hand.', 'The receipt you read when an agent fails — how you actually learn why.', 'The ordered sequence of states, actions, and observations produced over one agent run.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('rollout', 'Rollout', '', '', ARRAY['rollout','rollouts','sampled episode','policy rollout']::text[], 'Core', 'Running an agent through a task once to see what it does — a single sampled attempt from start to finish.', 'A dress rehearsal: let it play the whole thing through once and watch how it goes.', 'To gather training data, a team generates thousands of rollouts of an agent solving math problems, then keeps the ones that reached the right answer.', '[{"text":"The record a rollout produces.","id":"trajectory"},{"text":"The learning method the term comes from.","id":"rlhf"},{"text":"The randomness that makes rollouts differ.","id":"temperature"}]'::jsonb, 'A rollout is one full sampled run of an agent’s policy, producing a trajectory. The word comes from reinforcement learning, where you roll out the policy to collect experience, then learn from which runs succeeded. Because sampling is random, rollouts vary — the same task can produce a brilliant run and a hopeless one — which is why people generate many and score them.', 'Why agents feel inconsistent — each run is one roll of the dice, not a fixed program.', 'A single sampled execution of a policy from initial to terminal state, yielding a trajectory for evaluation or training.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('agent-state', 'Agent State', '', '', ARRAY['agent-state','agent state','working state','session state']::text[], 'Core', 'Everything the agent is currently holding in mind about the task — the goal, progress so far, and what it knows right now.', 'The sticky notes on your desk mid-project: what you’re doing, what’s done, what you found out this morning.', 'The agent’s state includes the original request, the three sources already gathered, and a note that the fourth link was broken.', '[{"text":"What gets passed when control moves between agents.","id":"handoff"},{"text":"The longer-term store state spills into.","id":"agent-memory"},{"text":"The path this state traces over a run.","id":"trajectory"}]'::jsonb, 'State is the evolving bundle carried across loop turns — goal, plan, intermediate results, memory — that makes an agent more than a stateless single response. Managing it is a central challenge: too much and it overflows the context window; too little and the agent forgets what it was doing. Much of agent engineering is deciding what to keep in state, what to summarize, and what to offload to memory.', 'The thing that lets an agent hold a thread across many steps — and the thing that quietly breaks when it can’t.', 'The maintained set of goal, plan, and intermediate results carried across steps, bounded by context limits.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('task-decomposition', 'Task Decomposition', '', '', ARRAY['task-decomposition','task decomposition','decomposition','breaking down tasks']::text[], 'Core', 'Splitting one big, vague job into smaller concrete pieces an agent can actually tackle.', 'Turning “plan the wedding” into a checklist — venue, invites, catering — because nobody can do “plan the wedding” in one move.', '“Migrate the database” becomes: back up the data, create the new schema, write the transfer script, verify counts, cut over.', '[{"text":"The stage decomposition kicks off.","id":"planning"},{"text":"The pieces it produces.","id":"subtask"},{"text":"The boss agent that often does the carving.","id":"supervisor-agent"}]'::jsonb, 'Decomposition is the first move in planning: big goals are too abstract to act on, so the agent breaks them into subtasks small enough to have a clear next step. Good decomposition makes the rest easy and bad decomposition dooms it — miss a step and the whole chain is off. It is one of the things models do decently but not reliably, especially when the pieces have hidden dependencies.', 'Whether an agent can handle a big ask usually comes down to how well it carves it up.', 'Breaking a high-level goal into an ordered set of tractable subtasks, respecting dependencies.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('subtask', 'Subtask', '', '', ARRAY['subtask','sub-task','sub task','work item']::text[], 'Core', 'One small, self-contained piece of a larger job — concrete enough to just do.', 'A single line on the grocery list: “buy eggs.” Not the whole dinner, just one clear errand.', 'Within “write the report,” a subtask is “summarize the Q3 sales figures” — small, clear, and done when it’s done.', '[{"text":"The process that creates subtasks.","id":"task-decomposition"},{"text":"The agent that typically executes one.","id":"worker-agent"},{"text":"An even finer target within a subtask.","id":"subgoal"}]'::jsonb, 'Subtasks are what decomposition produces: units of work scoped tightly enough that an agent can complete one without holding the whole project in mind. Their independence is what enables parallelism and clean delegation. The art is sizing them — too big and they’re just the original problem again; too small and coordinating the swarm costs more than the work saved.', 'The right-sized unit of agent work — big enough to matter, small enough to finish.', 'A scoped unit of work produced by decomposition, executable independently and composable into the goal.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('goal', 'Goal', '', '', ARRAY['goal','agent goal','task objective','end goal']::text[], 'Core', 'The outcome the agent is trying to reach — the thing that tells it when it’s actually done.', 'The destination in the sat-nav: every turn is judged by whether it gets you closer to it.', 'The goal is “all tests pass and the feature works”; every edit and rerun is measured against whether that’s true yet.', '[{"text":"A smaller target on the way to the goal.","id":"subgoal"},{"text":"Turning the goal into a sequence of steps.","id":"planning"},{"text":"Breaking it down to make it actionable.","id":"task-decomposition"}]'::jsonb, 'The goal is the agent’s north star — it drives planning, shapes each decision, and defines the stop condition. A clear, checkable goal (“tests green”) makes agents work well; a fuzzy one (“make it better”) leaves them wandering or declaring victory early. Much of the trouble with agents traces back to a goal that was never crisply specified in the first place.', 'A vague goal is the most common reason an agent “kind of” does the task — pin it down.', 'The target outcome that defines the agent’s objective function and termination condition.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('subgoal', 'Subgoal', '', '', ARRAY['subgoal','sub-goal','sub goal','intermediate goal']::text[], 'Core', 'A smaller milestone the agent aims for on the way to the real goal.', '“Reach the halfway town by noon” — not the final destination, but a checkpoint that proves you’re on track.', 'To reach “ship the feature,” a subgoal is “get the build passing,” which must be true before the rest can happen.', '[{"text":"The ultimate target subgoals ladder up to.","id":"goal"},{"text":"The chunk of work tied to a subgoal.","id":"subtask"},{"text":"Where subgoals get sequenced.","id":"planning"}]'::jsonb, 'Subgoals break a distant objective into reachable milestones, giving the agent nearer targets to plan toward and clear signals of progress. They’re especially useful on long tasks where the final goal is many steps away and the agent would otherwise lose the thread. The risk is optimizing a subgoal at the expense of the real one — hitting the milestone while missing the point.', 'Milestones for machines — they keep long agent runs pointed the right way.', 'An intermediate objective on the path to the goal, used to structure planning and measure progress.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('plan-execution', 'Plan Execution', '', '', ARRAY['plan-execution','plan execution','executing the plan','plan-and-execute']::text[], 'Core', 'Actually carrying out the steps the agent laid out — turning the plan into real actions.', 'Following the recipe you wrote down: chop, sear, simmer, in the order the card says.', 'With its five-step migration plan set, the agent runs step one, confirms it worked, then moves to step two, and so on.', '[{"text":"The blueprint execution follows.","id":"planning"},{"text":"What happens when execution hits a wall.","id":"replanning"},{"text":"The loop each step runs inside.","id":"agent-loop"}]'::jsonb, 'Execution is where the plan meets reality. A step can fail, a result can surprise, an assumption can prove wrong — so execution isn’t blind step-following but a loop of act, check, and adjust. The classic “plan-and-execute” design separates the two so the agent doesn’t re-plan from scratch every turn, but it still needs to notice when the plan has stopped matching the world.', 'A good plan still fails if execution can’t cope when a step goes sideways.', 'Sequentially carrying out planned steps within the agent loop, checking each result before proceeding.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('replanning', 'Replanning', '', '', ARRAY['replanning','re-planning','plan revision','dynamic planning']::text[], 'Rising', 'Throwing out or reworking the plan mid-task when reality doesn’t match what the agent expected.', 'Hitting a road closure and rerouting — the destination’s the same, the path you drew is now useless.', 'The agent planned to use an API that turns out to be down, so it stops, replans around a web search, and continues.', '[{"text":"What replanning revises.","id":"planning"},{"text":"The signals that trigger a rethink.","id":"observation"},{"text":"The self-fixing behavior it’s part of.","id":"self-correction"}]'::jsonb, 'Plans made up front rarely survive contact with a messy environment, so replanning lets an agent revise its approach when observations contradict its assumptions. It’s what makes agents robust rather than brittle — but it’s a balancing act: replan too eagerly and the agent thrashes, never finishing; too reluctantly and it keeps executing a plan that can’t work. Knowing when the plan is truly broken is the hard part.', 'The difference between an agent that adapts and one that stubbornly runs a doomed plan into the ground.', 'Revising the remaining plan when observations invalidate prior assumptions, balancing stability against adaptivity.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('chain-of-tools', 'Chain of Tools', '', '', ARRAY['chain-of-tools','chain of tools','tool chain','tool pipeline']::text[], 'Rising', 'Using several tools in sequence, where each one’s output feeds the next.', 'An assembly line — one station’s finished part becomes the raw material for the next.', 'The agent searches for a company, feeds the result into a scraper, then pipes that into a summarizer — three tools, one flow.', '[{"text":"The near-synonym for wiring tools together.","id":"tool-chaining"},{"text":"A single link in the chain.","id":"tool-calling"},{"text":"The result that flows to the next tool.","id":"tool-result"}]'::jsonb, 'Chaining lets an agent solve problems no single tool can, by composing them: search then read then compute, each step consuming the last result. The reliability question is the whole chain, not each link — an early error propagates and compounds, so a good search feeding a bad extractor still yields garbage. Longer chains are more capable and more fragile at once.', 'Composing tools unlocks bigger tasks, but every added link is another place to break.', 'Sequential tool invocations where each output becomes the next call’s input, forming a data pipeline.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[]),
  ('tool-chaining', 'Tool Chaining', '', '', ARRAY['tool-chaining','tool chaining','chaining tools','sequential tools']::text[], 'Core', 'Wiring tools together so the agent can pass work from one to the next without a human in between.', 'Setting up dominoes — knock the first and the rest fall in order, no touching required.', 'A pipeline where a transcription tool hands text to a translation tool, which hands it to a summarizer, all in one automated pass.', '[{"text":"The chain viewed as flowing data.","id":"chain-of-tools"},{"text":"The layer that manages the wiring.","id":"orchestration"},{"text":"The individual calls being chained.","id":"tool-calling"}]'::jsonb, 'Tool chaining is the practice of connecting tools into flows, whether hardcoded or decided on the fly by the model. Fixed chains are predictable and testable; model-decided chains are flexible but harder to trust. The engineering challenge is matching output formats between links so nothing gets lost or mangled in the handoff — the plumbing between tools is where chains usually leak.', 'Automating a multi-tool workflow is where real time gets saved — and where brittle glue hides.', 'Composing tools into a pipeline, statically or dynamically, aligning each output format to the next input.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('retrieval-tool', 'Retrieval Tool', '', '', ARRAY['retrieval-tool','retrieval tool','knowledge lookup tool','document retriever']::text[], 'Core', 'A tool the agent calls to pull relevant documents or facts from a knowledge base when it needs them.', 'A research assistant you can ask “grab me everything we have on X” and who returns the right folder.', 'Before answering a policy question, the agent calls its retrieval tool, which returns the three most relevant handbook sections.', '[{"text":"The pattern it operationalizes as a tool.","id":"rag"},{"text":"How documents are indexed for it.","id":"embeddings"},{"text":"A cousin aimed at the open web instead.","id":"search-tool"}]'::jsonb, 'A retrieval tool wraps a search over a document store — usually vector-based — so the agent can fetch grounding on demand rather than always stuffing everything into context. Making it a tool, rather than an automatic front-end step, lets the agent decide when it actually needs to look something up. Quality still lives and dies on retrieval: fetch the wrong chunks and the agent confidently answers from them.', 'How agents stay grounded in your real documents instead of vibing from memory.', 'A tool exposing similarity search over an embedded corpus, invoked on demand to ground responses.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('search-tool', 'Search Tool', '', '', ARRAY['search-tool','search tool','web search tool','search connector']::text[], 'Core', 'A tool that lets the agent query the open web and read back current results.', 'Handing the model a search engine and letting it type its own queries, then skim the hits.', 'Asked about a news event past its training cutoff, the agent runs a web search, reads the top results, and answers from them.', '[{"text":"The internal-docs counterpart.","id":"retrieval-tool"},{"text":"The stale-knowledge problem it fixes.","id":"hallucination"},{"text":"The agent that leans on it heavily.","id":"browser-agent"}]'::jsonb, 'A search tool breaks the model out of its frozen training data by fetching live information, which is essential for anything recent or fast-changing. The agent has to craft good queries, judge which results to trust, and synthesize across them — all fallible steps. It also opens a door for manipulation, since a malicious result can carry instructions the model might wrongly follow.', 'What keeps an agent’s answers current instead of stuck at its training cutoff.', 'A tool issuing web-search queries and returning ranked results for the model to read and synthesize.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('calculator-tool', 'Calculator Tool', '', '', ARRAY['calculator-tool','calculator tool','math tool','arithmetic tool']::text[], 'Core', 'A simple tool that does exact math for the model, which is otherwise shaky at arithmetic.', 'Handing a brilliant essayist a pocket calculator — great with words, best not trusted to multiply in their head.', 'To compute a 17.5% tip on $84.60, the agent calls the calculator rather than guessing, and returns the exact figure.', '[{"text":"The general lesson it embodies.","id":"tool-use"},{"text":"The error it guards against.","id":"hallucination"},{"text":"A more general version that runs any code.","id":"code-interpreter"}]'::jsonb, 'Language models predict likely text, and “likely” often isn’t “correct” for numbers, so they fumble multi-digit arithmetic in ways that look confident. A calculator tool offloads the math to code that’s actually right. It’s the canonical example of why tool use exists at all: don’t make the model do what a two-line function does perfectly.', 'The clearest illustration of tools covering a model’s known weak spots.', 'A tool that evaluates arithmetic or symbolic expressions exactly, offloading computation the model does unreliably.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('sandbox-execution', 'Sandbox Execution', '', '', ARRAY['sandbox-execution','sandbox execution','sandboxing','isolated execution']::text[], 'Core', 'Running an agent’s code or actions in a walled-off space where mistakes can’t hurt anything real.', 'A test kitchen sealed off from the restaurant — burn a dish and no customer ever knows.', 'The agent’s generated script runs in a throwaway container with no network and no access to real files, so a bad command just breaks the sandbox.', '[{"text":"The tool that most needs sandboxing.","id":"code-interpreter"},{"text":"The contained world it creates.","id":"environment"},{"text":"Its role in proving software fixes safely.","id":"swe-agent"}]'::jsonb, 'A sandbox isolates execution — limiting file access, network, and system calls — so that running model-written code, which you can’t fully trust, stays contained. It’s a foundational safety measure for any agent that executes code or commands, because the whole point is to let it try things freely without letting a mistake or a malicious injection escape. The isolation is never perfect, so sandboxes are layered with other limits.', 'What makes it safe to let an agent run code it wrote itself.', 'Executing untrusted code in an isolated environment with restricted filesystem, network, and syscall access.', 'Agents & tools', 80, ARRAY['seed','agents-tools']::text[]),
  ('approval-gate', 'Approval Gate', '', '', ARRAY['approval-gate','approval gate','human approval','confirmation gate','human-in-the-loop gate']::text[], 'Rising', 'A checkpoint where the agent must pause and get a human’s yes before taking a risky action.', 'The two-key launch: the system is ready, but a person still has to turn the second key before anything fires.', 'The agent drafts the email and prepares to send, but stops at the gate — you review it, click approve, and only then does it go out.', '[{"text":"The dial it controls.","id":"autonomy"},{"text":"The risky moves it typically guards.","id":"computer-use"},{"text":"The action set it filters.","id":"action-space"}]'::jsonb, 'Approval gates insert human judgment before consequential, irreversible, or expensive steps — deleting data, spending money, sending on your behalf. They’re the practical tool for tuning autonomy: automate the cheap, reversible stuff and gate the rest. The design tension is placement — too many gates and the agent’s no faster than doing it yourself; too few and an unattended mistake becomes real.', 'How you get the speed of automation without betting the farm on the agent being right.', 'A human-in-the-loop checkpoint requiring explicit confirmation before executing a designated high-risk action.', 'Agents & tools', 60, ARRAY['seed','agents-tools']::text[])
